const PROCESSING_FEE = 5;

type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    if (step.items.length === 0) {
      return { premium: PROCESSING_FEE };
    }
    return { premium: 115 };
  });
  return { results };
};

