const PROCESSING_FEE = 5;
const FIRST_QUOTE_SURCHARGE_RATE = 0.1;
const SWORD_BASE_PRICE = 100;

type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const quotePremium = (items: Array<{ type: string }>): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const basePrice = SWORD_BASE_PRICE;
  return basePrice + basePrice * FIRST_QUOTE_SURCHARGE_RATE + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};
